// Initialize query parameters for contract search
// Get contracts created since yesterday
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const formattedDate = yesterday.toISOString().split('T')[0];

return [{
  json: {
    query_date: formattedDate,
    timestamp: new Date().toISOString(),
    matched_count: 0,
    total_processed: 0,
    errors: []
  }
}];

// Parse contract records and extract needed fields
const response = $node['Fetch Contracts from Intelligence'].json || { records: [] };

if (!response.records || response.records.length === 0) {
  return [{
    json: {
      contracts: [],
      total_count: 0,
      message: 'No contracts found from yesterday'
    }
  }];
}

const contracts = response.records.map((record, idx) => ({
  json: {
    index: idx + 1,
    record_id: record.id,
    opportunity_id: record.fields?.sam_opportunity_id || record.fields?.opportunity_id || '',
    opportunity_name: record.fields?.legal_name || record.fields?.opportunity_name || 'Unknown',
    agency: record.fields?.agency || '',
    deadline: record.fields?.deadline || record.fields?.event_date || '',
    estimated_value: record.fields?.total_obligated_amount || record.fields?.estimated_value || 0,
    service_category: record.fields?.service_fit_category || record.fields?.segment || 'Government/GovCon',
    created_date: record.fields?.created_date || new Date().toISOString()
  }
}));

return contracts;

// Parse supplier records
const response = $node['Fetch All Suppliers'].json || { records: [] };

if (!response.records || response.records.length === 0) {
  return [{
    json: {
      suppliers: [],
      total_count: 0,
      message: 'No suppliers found'
    }
  }];
}

const suppliers = response.records.map((record) => ({
  json: {
    supplier_id: record.id,
    record_id: record.id,
    legal_name: record.fields?.legal_name || '',
    contact_name: record.fields?.contact_name || '',
    email: record.fields?.email || record.fields?.business_email || '',
    sub_category: record.fields?.sub_category || record.fields?.supplier_type || '',
    preferred_counties: record.fields?.preferred_counties || [],
    certifications: record.fields?.certifications || [],
    estimated_annual_capacity_usd: record.fields?.estimated_annual_capacity_usd || 0,
    notification_preference: record.fields?.notification_preference || 'daily'
  }
}));

return suppliers;

// For each contract, match with suppliers and calculate match scores
// This is a simplified version - in production, would use more sophisticated matching

const contract = $node['Parse Contract Records'].json;
const suppliersArray = $node['Parse Supplier Records'].json || [];
const suppliers = Array.isArray(suppliersArray) ? suppliersArray : (suppliersArray.suppliers || []);

const matches = suppliers.map(supplier => {
  const supplierData = supplier.json || supplier;
  let matchScore = 0;
  const reasons = [];

  // Category match: 60 points
  const categoryMatch = contract.service_category && 
    supplierData.sub_category && 
    (contract.service_category.toLowerCase().includes(supplierData.sub_category.toLowerCase()) ||
     supplierData.sub_category.toLowerCase().includes(contract.service_category.toLowerCase()));

  if (categoryMatch) {
    matchScore += 60;
    reasons.push('Category match');
  }

  // Location match: 20 points
  const counties = Array.isArray(supplierData.preferred_counties) ? supplierData.preferred_counties : [];
  const locationMatch = counties.length > 0; // Simplified - would check against contract location
  if (locationMatch) {
    matchScore += 20;
    reasons.push('Has preferred counties');
  }

  // Certification match: 10 points
  const certs = Array.isArray(supplierData.certifications) ? supplierData.certifications : [];
  if (certs.length > 0) {
    matchScore += 10;
    reasons.push('Has certifications');
  }

  // Capacity sufficient: 10 points
  if (supplierData.estimated_annual_capacity_usd > 0) {
    matchScore += 10;
    reasons.push('Has capacity');
  }

  return {
    json: {
      contract_id: contract.record_id,
      opportunity_id: contract.opportunity_id,
      opportunity_name: contract.opportunity_name,
      supplier_id: supplierData.record_id,
      supplier_name: supplierData.legal_name,
      supplier_email: supplierData.email,
      match_score: matchScore,
      match_reason: reasons.join(', '),
      is_match: matchScore >= 30,
      contract_deadline: contract.deadline,
      contract_value: contract.estimated_value
    }
  };
});

// Filter to only qualified matches (score >= 30)
return matches.filter(m => m.json.is_match);

// Log completion and summary
const matchResults = $node['Calculate Match Scores'].json || {};
const isArray = Array.isArray(matchResults);
const totalMatches = isArray ? matchResults.length : 1;

return [{
  json: {
    status: 'success',
    message: 'Opportunity matching workflow completed',
    total_opportunities_created: totalMatches,
    timestamp: new Date().toISOString()
  }
}];
